"use client";

import type { ReactNode } from "react";
import { mixOklch, type RemocnTheme, useRemocnTheme } from "@/lib/remocn-ui";

export type ToggleGroupState = string;

export type ToggleGroupSize = "default" | "sm";

export interface ToggleGroupItem {
  value: string;
  label: string;
  icon?: ReactNode;
}

export interface ToggleGroupProps {
  state?: ToggleGroupState;
  style?: ToggleGroupStyle;
  items?: ToggleGroupItem[];
  size?: ToggleGroupSize;
  theme?: Partial<RemocnTheme>;
  align?: "start" | "center" | "end";
  className?: string;
}

function justify(align: "start" | "center" | "end"): string {
  return align === "start"
    ? "flex-start"
    : align === "end"
      ? "flex-end"
      : "center";
}

const DEFAULT_ITEMS: ToggleGroupItem[] = [
  { value: "Monthly", label: "Monthly" },
  { value: "Yearly", label: "Yearly" },
];

const SIZE_STYLES: Record<
  ToggleGroupSize,
  {
    height: number;
    segMinWidth: number;
    fontSize: number;
    pad: number;
    gap: number;
  }
> = {
  sm: { height: 32, segMinWidth: 72, fontSize: 13, pad: 3, gap: 6 },
  default: { height: 36, segMinWidth: 88, fontSize: 14, pad: 4, gap: 8 },
};

export interface ToggleGroupStyle {
  indicatorOffset: number;
}

export interface ToggleGroupStyleContext {
  items: ToggleGroupItem[];
  trackBg: string;
  thumbBg: string;
  activeFg: string;
  inactiveFg: string;
  radius: number;
}

export function toggleGroupStyleContext(
  items: ToggleGroupItem[],
  theme: RemocnTheme,
): ToggleGroupStyleContext {
  return {
    items,
    trackBg: theme.muted,
    thumbBg: theme.background,
    activeFg: theme.foreground,
    inactiveFg: theme.mutedForeground,
    radius: theme.radius,
  };
}

export function toggleGroupStyle(
  state: ToggleGroupState,
  ctx: ToggleGroupStyleContext,
): ToggleGroupStyle {
  const i = ctx.items.findIndex((it) => it.value === state);
  return { indicatorOffset: i < 0 ? 0 : i };
}

export function ToggleGroup({
  state = DEFAULT_ITEMS[0].value,
  style,
  items = DEFAULT_ITEMS,
  size = "default",
  theme: themeOverride,
  align = "center",
  className,
}: ToggleGroupProps) {
  const theme = useRemocnTheme(themeOverride, "light");
  const ctx = toggleGroupStyleContext(items, theme);
  const v = style ?? toggleGroupStyle(state, ctx);

  const sizeStyle = SIZE_STYLES[size];
  const { pad } = sizeStyle;
  const segmentWidth = sizeStyle.segMinWidth;
  const thumbX = pad + v.indicatorOffset * segmentWidth;

  return (
    <div
      className={className}
      style={{
        position: "absolute",
        inset: 0,
        display: "flex",
        alignItems: "center",
        justifyContent: justify(align),
        background: "transparent",
        fontFamily:
          "var(--font-geist-sans), -apple-system, BlinkMacSystemFont, sans-serif",
      }}
    >
      <div
        style={{
          position: "relative",
          display: "flex",
          height: sizeStyle.height,
          padding: pad,
          boxSizing: "border-box",
          background: ctx.trackBg,
          borderRadius: ctx.radius,
        }}
      >
        {}
        <div
          style={{
            position: "absolute",
            top: pad,
            left: thumbX,
            width: segmentWidth,
            height: sizeStyle.height - pad * 2,
            background: ctx.thumbBg,
            borderRadius: Math.max(2, ctx.radius - 3),
            boxShadow: "0 1px 2px rgba(0,0,0,0.1)",
          }}
        />
        {}
        {items.map((item, i) => {
          const proximity = Math.max(0, 1 - Math.abs(i - v.indicatorOffset));
          return (
            <span
              key={item.value}
              style={{
                position: "relative",
                width: segmentWidth,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                gap: sizeStyle.gap,
                fontSize: sizeStyle.fontSize,
                fontWeight: 500,
                letterSpacing: "-0.01em",
                color: mixOklch(ctx.inactiveFg, ctx.activeFg, proximity),
              }}
            >
              {item.icon}
              {item.label}
            </span>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import {
  type ToggleGroupItem,
  type ToggleGroupState,
  type ToggleGroupStyle,
  toggleGroupStyle,
  toggleGroupStyleContext,
} from "@/components/remocn/toggle-group";
import {
  easings,
  type RemocnTheme,
  type Step,
  useRemocnTheme,
  useStateTransition,
} from "@/lib/remocn-ui";

const DEFAULT_ITEMS: ToggleGroupItem[] = [
  { value: "Monthly", label: "Monthly" },
  { value: "Yearly", label: "Yearly" },
];

export const DEFAULT_DURATION = 14;

export function tweenToggleGroupStyle(
  a: ToggleGroupStyle,
  b: ToggleGroupStyle,
  t: number,
): ToggleGroupStyle {
  return {
    indicatorOffset:
      a.indicatorOffset + (b.indicatorOffset - a.indicatorOffset) * t,
  };
}

export interface ToggleGroupTransitionOptions {
  items?: ToggleGroupItem[];
  theme?: Partial<RemocnTheme>;
  mode?: "light" | "dark";
  speed?: number;
  defaultDuration?: number;
}

export function useToggleGroupTransition(
  steps: Step<ToggleGroupState>[],
  opts: ToggleGroupTransitionOptions = {},
): ToggleGroupStyle {
  const {
    items = DEFAULT_ITEMS,
    theme: themeOverride,
    mode,
    speed = 1,
    defaultDuration = DEFAULT_DURATION,
  } = opts;
  const theme = useRemocnTheme(themeOverride, mode);
  const ctx = toggleGroupStyleContext(items, theme);
  const { from, to, progress } = useStateTransition(
    steps,
    items[0].value,
    speed,
    defaultDuration,
  );
  const t = easings.out(progress);
  return tweenToggleGroupStyle(
    toggleGroupStyle(from, ctx),
    toggleGroupStyle(to, ctx),
    t,
  );
}
